/**
 * @name ThemeResource path traversal - HTTP path to resource loading
 * @description HTTP path parameter flows to classpath resource loading without path containment check
 * @kind path-problem
 * @problem.severity error
 * @id java/keycloak-theme-resource-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ThemeResourceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Sources from ThemeResource specifically - path parameters
    exists(MethodCall mc |
      mc.getMethod().hasName("getPathParameters") or
      mc.getMethod().hasName("getPathParam") or
      mc.getMethod().hasName("getQueryParameters") or
      mc.getMethod().hasName("getQueryParam") |
      source.asExpr() = mc
    )
    or
    // JAX-RS @PathParam annotation
    exists(Parameter p |
      p.getAnAnnotation().getType().hasQualifiedName("javax.ws.rs", "PathParam") or
      p.getAnAnnotation().getType().hasQualifiedName("javax.ws.rs", "QueryParam") |
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource/getResourceAsStream
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // File construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Barrier on calls to canonical path
    exists(MethodCall mc |
      (mc.getMethod().hasName("getCanonicalPath") or mc.getMethod().hasName("normalize") or
       mc.getMethod().hasName("toRealPath")) |
      node.asExpr() = mc
    )
  }
}

module ThemeResourceFlow = TaintTracking::Global<ThemeResourceConfig>;
import ThemeResourceFlow::PathGraph

from ThemeResourceFlow::PathNode source, ThemeResourceFlow::PathNode sink
where ThemeResourceFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: HTTP parameter flows to file/resource loading from $@.", source.getNode(), "user input"

/**
 * @name FolderTheme direct File construction from user path - no canonical check
 * @description FolderTheme constructs File directly from user-supplied path parameter
 *              without calling getCanonicalPath() or checking containment
 * @kind path-problem
 * @problem.severity error
 * @id java/keycloak-folder-theme-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module FolderThemeConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HTTP path parameter from ThemeResource
    exists(Parameter p |
      p.getAnAnnotation().getType().hasQualifiedName("javax.ws.rs", "PathParam") and
      source.asParameter() = p
    )
    or
    // getQueryParameters/getPathParameters
    exists(MethodCall mc |
      (mc.getMethod().hasName("getPathParameters") or
       mc.getMethod().hasName("getQueryParameters")) |
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor in FolderTheme 
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      (ce.getEnclosingCallable().getDeclaringType().hasName("FolderTheme") or
       ce.getEnclosingCallable().getDeclaringType().hasName("FolderThemeProvider")) and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("getCanonicalPath") or
       mc.getMethod().hasName("toRealPath")) |
      node.asExpr() = mc
    )
  }
}

module FolderThemeFlow = TaintTracking::Global<FolderThemeConfig>;
import FolderThemeFlow::PathGraph

from FolderThemeFlow::PathNode source, FolderThemeFlow::PathNode sink
where FolderThemeFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "FolderTheme path traversal: HTTP path param flows to File constructor without canonical check, from $@.", source.getNode(), "user-supplied path"
